namespace sv_cf6f3e968e29428684febd41b3858f9d.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

/// <summary>
/// Mutable form state classes used for two-way binding in the multi-step form.
/// Converted to immutable records on submission.
/// </summary>
public class ApplicationFormState
{
    public PersonalInfoForm Personal { get; set; } = new();
    public List<WorkEntryForm> WorkEntries { get; set; } = [new()];
    public List<ReferenceForm> References { get; set; } = [new(), new()];
    public string CoverLetter { get; set; } = string.Empty;

    public JobApplication ToRecord() => new(
        Personal.ToRecord(),
        new WorkHistory(WorkEntries.Select(w => w.ToRecord()).ToList()),
        References.Select(r => r.ToRecord()).ToList(),
        CoverLetter
    );
}

public class PersonalInfoForm
{
    public string FullName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryForm
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = string.Empty;

    public WorkEntry ToRecord() => new(Company, Title, StartDate ?? DateTime.Today, IsCurrent ? null : EndDate, Description);
}

public class ReferenceForm
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

using sv_cf6f3e968e29428684febd41b3858f9d.Models;

namespace sv_cf6f3e968e29428684febd41b3858f9d.Services;

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@namespace sv_cf6f3e968e29428684febd41b3858f9d.Components.Pages.Apply

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="list-unstyled d-flex justify-content-between align-items-center m-0 p-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var status = GetStepStatus(stepIndex);
            <li class="step-item text-center flex-fill @status" role="listitem">
                @if (status == "completed")
                {
                    <button class="btn btn-link step-circle-link p-0" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">✓</span>
                    </button>
                }
                else
                {
                    <span class="step-circle @(status == "active" ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">
                        @(stepIndex + 1)
                    </span>
                }
                <div class="step-label small mt-1 @(status == "dimmed" ? "text-muted" : "")">
                    @StepNames[stepIndex]
                </div>
            </li>
            @if (stepIndex < StepNames.Count - 1)
            {
                <li class="step-connector flex-fill" role="presentation" aria-hidden="true">
                    <hr class="@(stepIndex < CurrentStep ? "border-success" : "border-secondary opacity-25")" />
                </li>
            }
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepStatus(int index)
    {
        if (index < CurrentStep) return "completed";
        if (index == CurrentStep) return "active";
        return "dimmed";
    }
}

@namespace sv_cf6f3e968e29428684febd41b3858f9d.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @(EmailError is not null ? "is-invalid" : "")"
           @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
    @if (EmailError is not null)
    {
        <div class="invalid-feedback">@EmailError</div>
    }
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
</div>

<div class="mb-3">
    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
</div>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoForm Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ValidationError;
    private string? EmailError;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ValidationError = null;
        EmailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ValidationError = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var isValid = await ValidateEmail(Model.Email);
            if (!isValid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_cf6f3e968e29428684febd41b3858f9d.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Company <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="entry.Company" @bind:event="oninput" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="entry.Title" @bind:event="oninput" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <div class="form-check mb-2">
                        <input type="checkbox" class="form-check-input" id="current-@index"
                               @bind="entry.IsCurrent" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
                <div class="col-12">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="3" @bind="entry.Description" @bind:event="oninput"></textarea>
                </div>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary mb-3" @onclick="AddEntry">+ Add Another Position</button>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryForm> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private void AddEntry() => Entries.Add(new WorkEntryForm());

    private void RemoveEntry(int index) => Entries.RemoveAt(index);

    private async Task HandleNext()
    {
        ValidationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                ValidationError = "Company, job title, and start date are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_cf6f3e968e29428684febd41b3858f9d.Components.Pages.Apply

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="reference.Name" @bind:event="oninput" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="reference.Relationship" @bind:event="oninput" placeholder="e.g., Former Manager" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="reference.Email" @bind:event="oninput" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="reference.Phone" @bind:event="oninput" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-primary mb-3" @onclick="AddReference">+ Add Reference</button>
}

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceForm> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private void AddReference()
    {
        if (References.Count < 3) References.Add(new ReferenceForm());
    }

    private void RemoveReference(int index) => References.RemoveAt(index);

    private async Task HandleNext()
    {
        ValidationError = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                ValidationError = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_cf6f3e968e29428684febd41b3858f9d.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-2">
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              @bind="FormState.CoverLetter" @bind:event="oninput"
              placeholder="Write your cover letter here…"></textarea>
</div>

<div class="text-muted small mb-3">
    @FormState.CoverLetter.Length / @MaxLength characters
</div>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public ApplicationFormState FormState { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private async Task HandleNext()
    {
        ValidationError = null;

        if (string.IsNullOrWhiteSpace(FormState.CoverLetter))
        {
            ValidationError = "A cover letter is required.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_cf6f3e968e29428684febd41b3858f9d.Components.Pages.Apply

<h4 class="mb-3">Review & Submit</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center">
        <h5>🎉 Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-sm btn-outline-primary" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt>
                <dd class="col-sm-9">@FormState.Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@FormState.Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@FormState.Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@FormState.Personal.Address</dd>
            </dl>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-sm btn-outline-primary" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in FormState.WorkEntries)
            {
                <div class="mb-3 border-bottom pb-2">
                    <strong>@entry.Title</strong> at <em>@entry.Company</em><br />
                    <small class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-sm btn-outline-primary" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in FormState.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <small>@r.Email · @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-sm btn-outline-primary" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@FormState.CoverLetter</p>
        </div>
    </div>

    @if (SubmitError is not null)
    {
        <div class="alert alert-danger">@SubmitError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack" disabled="@IsSubmitting">← Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
