                <div class="mb-3 border-bottom pb-2">
                    <strong>@entry.Title</strong> at <em>@entry.Company</em><br />
                    <small class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-sm btn-outline-primary" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in FormState.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <small>@r.Email · @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-sm btn-outline-primary" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@FormState.CoverLetter</p>
        </div>
    </div>

    @if (SubmitError is not null)
    {
        <div class="alert alert-danger">@SubmitError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack" disabled="@IsSubmitting">← Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public ApplicationFormState FormState { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> SubmitApplication { get; set; } = default!;

    private bool IsSubmitting;
    private bool IsSubmitted;
    private int ApplicationId;
    private string? SubmitError;

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        SubmitError = null;
        try
        {
            ApplicationId = await SubmitApplication();
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            SubmitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}
"}

{"path": "/tmp/sv-cf6f3e968e29428684febd41b3858f9d/Components/Pages/Apply/Apply.razor", "file_text": "@page "/apply"
@using sv_cf6f3e968e29428684febd41b3858f9d.Models
@using sv_cf6f3e968e29428684febd41b3858f9d.Services
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" StepNames="StepNames" OnStepClicked="GoToCompletedStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="formState.Personal"
                              OnNext="NextStep"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;
        case 1:
            <WorkHistoryStep Entries="formState.WorkEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="formState.References"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep FormState="formState"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep FormState="formState"
                        OnBack="PreviousStep"
                        OnEditStep="GoToStep"
                        SubmitApplication="SubmitAsync" />
            break;
    }
</div>

@code {
    private static readonly IReadOnlyList<string> StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int currentStep;
    private readonly ApplicationFormState formState = new();

    private void NextStep() => currentStep = Math.Min(currentStep + 1, StepNames.Count - 1);

    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);

    private void GoToStep(int step) => currentStep = Math.Clamp(step, 0, StepNames.Count - 1);

    private void GoToCompletedStep(int step)
    {
        if (step < currentStep) currentStep = step;
    }

    private async Task<int> SubmitAsync()
    {
        var application = formState.ToRecord();
        return await ApplicationService.SubmitApplicationAsync(application);
    }
}
"}

